EST['_search']:false; 		$filterRules =  isset($_POST['filters'])?$_POST['filters']:false;				$limit =  $rows;		$offset =  $rows * ($page - 1);				$order = isset($_REQUEST['order']) ? $_REQUEST['order'] : array();				if($sord == 'asc'){			$sord = 1;		} else {			$sord = 2;		}				$sort =	$sidx. '='.$sord;							if(strlen(trim($date_start)) == 0 ){			$date_start = '1900-01-01';		}				if(strlen(trim($date_end)) == 0 ){			$date_end = '9999-12-31';		}		$where='';		if($item_id !=0){			$where="where a.item_id='".$item_id."'";		}		//($tglAwal=null,$tglAkhir=null,$order=null,$limit=null,$offset=0){		//"tanggal_saldo":"123456","tanggal_stok":"123456","nama_pt":"POP STAR, PT","periode_name":"2024-07-20 To 2024-08-20","max_decimal_digit_jumlah":"4","max_decimal_digit_price":"4",		//var_dump($date_start);		$data['xrow']=$this->main->get_tracing_bahan_baku($date_start,$date_end,$where,$sort,$limit,$offset);		$jumlah=$this->main->jumlah_tracing_bahan_baku($date_start,$date_end,$where);		$periode_name=array("tanggal_saldo"=>'123456',"tanggal_stok"=>'123456',"nama_pt"=>'POP STAR, PT',"periode_name"=>"2024-07-20 To 2024-08-20","max_decimal_digit_jumlah"=>'4',"max_decimal_digit_price"=>'4');		$jumlah_data=array("result_count"=>$jumlah[0]['count']);								//$count['result_count']=		$data['detail']=array_merge($periode_name, $jumlah_data);		//$hasil['detail']=$detail;		//$data_result = json_decode($result['data'],true);		//$data_all['data']=array($data);		//$data_result = json_decode($data_all['data'],true);				   if(isset($data['detail']['result_count'])){				$records = $data['detail']['result_count'];				$total = ceil($data['detail']['result_count'] / $limit);			} else {				$records = 0;				$total = 0;			}						$responce = new stdclass();			$responce->page = $page;			$responce->records = $records;			$responce->total = $total;			$i=0; 			//if($data_result){				if(isset($data['xrow'])){					foreach($data['xrow'] as $key=>$value){						foreach ($value as $k => $v) {							$responce->rows[$i][$k] = $v;						} 						$i++;					}				}			//}					echo json_encode($responce);				//	var_dump($responce);die();	}				function loaddatax(){				$field = $this->tracing_sumber_pemasukan_table();				$date_start = isset($_REQUEST['date_start']) ?  $_REQUEST['date_start'] : '';		$date_end = isset($_REQUEST['date_end']) ? $_REQUEST['date_end'] : '';		$print = isset($_REQUEST['print']) ? $_REQUEST['print'] : 0;		$format = isset($_REQUEST['format']) ? $_REQUEST['format'] : 'xlsx';		$page = isset($_POST['page'])?$_POST['page']:1; // get the requested page         $rows = isset($_POST['rows'])?$_POST['rows']:10; // get how many rows we want to have into the grid         $sidx = isset($_POST['sidx'])?$_POST['sidx']:'bc_date'; // get index row - i.e. user click to sort         $sord = isset($_POST['sord'])?$_POST['sord']:'0'; // get the direction 		$search = isset($_REQUEST['_search'])?$_REQUEST['_search']:false; 		$filterRules =  isset($_POST['filters'])?$_POST['filters']:false;						$limit =  $rows;		$offset =  $rows * ($page - 1);				$order = isset($_REQUEST['order']) ? $_REQUEST['order'] : array();				if($sord == 'asc'){			$sord = 1;		} else {			$sord = 2;		}				$sort =	$sidx. '='.$sord;							if(strlen(trim($date_start)) == 0 ){			$date_start = '1900-01-01';		}				if(strlen(trim($date_end)) == 0 ){			$date_end = '9999-12-31';		}				$return = array();		$return['valid'] = false;		$return['message'] = "Internal Server Error";										$sp = "dbo.sp_rpt_tracing_pemasukan";				if($print == 1){			$this->rpc_service->setSP(array("sp"=> $sp,"mode"=> $print == 1 ? "2" : "1","debug"=>"1"));		} else {			$this->rpc_service->setSP($sp);		}				$this->rpc_service->addField('date_start',$date_start);		$this->rpc_service->addField('date_end',$date_end);		$this->rpc_service->addField('format',$format);		$this->rpc_service->addField('temp_folder',sys_get_temp_dir());		$this->rpc_service->addField('sort',$sort);		$this->rpc_service->addField('limit',$limit);		$this->rpc_service->addField('offset',$offset);				$this->rpc_service->setWhere($search,$filterRules,$field);				if($print == 1){						$result = $this->rpc_service->resultPrint2();			echo json_encode($result);		} else {			$this->authentication->plainlayout();									$result = $this->rpc_service->resultJSON();				$data_result = json_decode($result['data'],true);						if(isset($data_result['detail']['result_count'])){				$records = $data_result['detail']['result_count'];				$total = ceil($data_result['detail']['result_count'] / $limit);			} else {				$records = 0;				$total = 0;			}						$responce = new stdclass();			$responce->page = $page;			$responce->records = $records;			$responce->total = $total;			$i=0; 			if($data_result){				if(isset($data_result['xrow'])){					foreach($data_result['xrow'] as $key=>$value){						foreach ($value as $k => $v) {							$responce->rows[$i][$k] = $v;						} 						$i++;					}				}			}					echo json_encode($responce);		}	}}?>